  "device_identifier": "UbuntuComputer",
  "commands": [
    "bash -lc 'cat > /etc/apparmor.d/usr.bin.splunkd << \"EOF\"\\n#include <tunables/global>\\nprofile splunkd /usr/bin/splunkd {\\n  /usr/src/app/splunkd/** r,\\n  /usr/src/app/splunkd/** rwk,\\n  /var/log/splunk/** rwk,\\n  /etc/splunk/** r,\\n  /proc/** r,\\n  /sys/** r,\\n  /bin/sh ix,\\n  network inet stream,\\n}\\nEOF'"},
    "bash -lc 'apparmor_parser -r /etc/apparmor.d/usr.bin.splunkd'"},
    "bash -lc 'aa-status | head -n 50'"
  ]
}

